import java.io.*;
import java.util.*;

public class Main {
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do {
                c = readByte();
                if (c == -1) return Integer.MIN_VALUE; // end of stream
            } while (c <= ' ');
            if (c == '-' ) { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }

    private static int upperBound(int[] row, int val) {
        int lo = 0, hi = row.length;
        while (lo < hi) {
            int mid = (lo + hi) >>> 1;
            if (row[mid] <= val) lo = mid + 1; else hi = mid;
        }
        return lo;
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder sb = new StringBuilder();
        int T = fs.nextInt();
        for (int t = 0; t < T; t++) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            int[][] mat = new int[N][M];
            int low = Integer.MAX_VALUE;
            int high = Integer.MIN_VALUE;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    int val = fs.nextInt();
                    mat[i][j] = val;
                    if (j == 0) low = Math.min(low, val);
                    if (j == M - 1) high = Math.max(high, val);
                }
            }
            int need = (N * M + 1) / 2;
            while (low < high) {
                int mid = low + (high - low) / 2;
                long cnt = 0;
                for (int i = 0; i < N; i++) cnt += upperBound(mat[i], mid);
                if (cnt < need) low = mid + 1; else high = mid;
            }
            sb.append(low);
            if (t != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

